import React, { useEffect, useState } from 'react';
import API from '../services/api';
import ProductCard from '../components/ProductCard';

const Home = () => {
  const [featured, setFeatured] = useState([]);
  const [bestSellers, setBestSellers] = useState([]);
  const [discounted, setDiscounted] = useState([]);
  const [categories, setCategories] = useState([]);

  useEffect(() => {
    const fetchProducts = async () => {
      const { data } = await API.get('/products?limit=100');
      if (data.success) {
        const all = data.products;
        setFeatured(all.filter(p => p.featured).slice(0, 4));
        setBestSellers([...all].sort((a, b) => b.rating - a.rating).slice(0, 4));
        setDiscounted(all.filter(p => p.discount > 0).slice(0, 4));
        const cats = [...new Set(all.map(p => p.category))];
        setCategories(cats);
      }
    };
    fetchProducts();
  }, []);

  return (
    <div className="container my-4">
      <h2 className="mb-3">Featured</h2>
      <div className="row">
        {featured.map(product => (
          <div className="col-md-3" key={product._id}>
            <ProductCard product={product} />
          </div>
        ))}
      </div>

      <h2 className="my-3">Best Sellers</h2>
      <div className="row">
        {bestSellers.map(product => (
          <div className="col-md-3" key={product._id}>
            <ProductCard product={product} />
          </div>
        ))}
      </div>

      <h2 className="my-3">Discounted</h2>
      <div className="row">
        {discounted.map(product => (
          <div className="col-md-3" key={product._id}>
            <ProductCard product={product} />
          </div>
        ))}
      </div>

      {categories.map(cat => (
        <div key={cat}>
          <h2 className="my-3">Category: {cat}</h2>
          {/* Optionally render products of this category here */}
        </div>
      ))}
    </div>
  );
};

export default Home;
